const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
  return combined.map(item => ({ json: item.json }));

// Node 1 (parallel branch A): fetch ALL existing grant source_ids for this org
// in a single Supabase query. Used downstream to filter out grants already tracked.

let orgId;
try { orgId = $('Fetch Grants Webhook').first().json.body?.org_id; } catch(e) {}
if (!orgId) return [{ json: { existingIds: [] } }];

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

let existingIds = [];
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/grants?org_id=eq.' + encodeURIComponent(orgId) + '&select=source_id&limit=100000',
    headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey },
  });
  if (Array.isArray(res)) existingIds = res.map(r => (r.source_id || '').trim()).filter(Boolean);
} catch(e) {}

return [{ json: { existingIds } }];

// Node 2 (parallel branch B): fetch org profile + supporting documents.
// Primary niche context is built from the organizations row fields directly
// (mission, description, executive_summary, sector, programs, geographic_focus).
// Document extracted_text is appended as supporting context, tightly capped
// so the prompt stays within reasonable size for the discovery AI.

let orgId;
try { orgId = $('Fetch Grants Webhook').first().json.body?.org_id; } catch(e) {}
if (!orgId) return [{ json: { error: true, message: 'No org_id' } }];

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const headers = { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey };

const ORG_SELECT = 'id,name,mission,description,executive_summary,sector,programs,geographic_focus,address';

const [orgs, docs] = await Promise.all([
  this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/organizations?id=eq.' + encodeURIComponent(orgId) + '&select=' + ORG_SELECT,
    headers,
  }).catch(() => []),
  this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/documents?org_id=eq.' + encodeURIComponent(orgId) + '&extraction_status=eq.completed&select=title,category,extracted_text&order=updated_at.desc&limit=10',
    headers,
  }).catch(() => []),
]);

if (!Array.isArray(orgs) || orgs.length === 0) {
  return [{ json: { error: true, message: 'Organization not found: ' + orgId } }];
}
const org = orgs[0];

// Structured profile from organizations columns (primary source)
const profileParts = [];
if (org.name) profileParts.push('Organization: ' + org.name);
if (org.mission) profileParts.push('Mission: ' + org.mission);
if (org.description) profileParts.push('Description: ' + org.description);
if (org.executive_summary) profileParts.push('Executive Summary: ' + org.executive_summary);
if (org.sector) profileParts.push('Sector: ' + org.sector);
if (Array.isArray(org.programs) && org.programs.length > 0) {
  profileParts.push('Programs: ' + org.programs.map(p => typeof p === 'string' ? p : (p && (p.name || p.title)) || '').filter(Boolean).join(', '));
} else if (typeof org.programs === 'string' && org.programs) {
  profileParts.push('Programs: ' + org.programs);
}
if (org.geographic_focus) {
  const geo = Array.isArray(org.geographic_focus) ? org.geographic_focus.join(', ') : org.geographic_focus;
  if (geo) profileParts.push('Geographic Focus: ' + geo);
}
if (org.address) profileParts.push('Address: ' + org.address);

let nicheSummary = profileParts.join('\n');

// Supporting document excerpts (optional, tightly capped)
if (Array.isArray(docs) && docs.length > 0) {
  const PER_DOC_LIMIT = 1500;
  const TOTAL_DOC_LIMIT = 6000;
  let used = 0;
  const docParts = [];
  for (const d of docs) {
    const text = (d.extracted_text || '').trim();
    if (!text) continue;
    const chunk = text.slice(0, PER_DOC_LIMIT);
    if (used + chunk.length > TOTAL_DOC_LIMIT) break;
    const label = d.category || d.title || 'Document';
    docParts.push('[' + label + '] ' + chunk);
    used += chunk.length;
  }
  if (docParts.length > 0) {
    nicheSummary += (nicheSummary ? '\n\n' : '') + 'Supporting documents:\n' + docParts.join('\n\n');
  }
}

return [{ json: { org, nicheSummary } }];

// Node 3: filter grants that are already tracked, normalize shape for sub-workflow.
// Pulls raw grants from the Combine node and existingIds from branch A.

const allItems = $('Combine & Deduplicate All Sources5').all().map(i => i.json);
const existingIds = new Set(($('Fetch Existing Grant IDs').first().json.existingIds) || []);

const newGrants = [];
for (const grant of allItems) {
  const oppNum = (grant.oppNum || '').trim();
  if (!oppNum || existingIds.has(oppNum)) continue;
  newGrants.push(grant);
}

if (newGrants.length === 0) {
  return [{ json: { noNewGrants: true, count: 0 } }];
}

const normalized = newGrants.map(grant => ({
  title: grant.title || '',
  agency: grant.agency || null,
  agencyCode: grant.agencyCode || '',
  description: grant.description || '',
  awardFloor: grant.awardFloor || 0,
  awardCeiling: grant.awardCeiling || 0,
  openDate: grant.openDate || '',
  closeDate: grant.closeDate || '',
  status: grant.status || '',
  source: grant.source || 'Grant Scanner',
  source_id: grant.oppNum || grant.source_id,
  source_url: grant.link || grant.source_url,
  oppNum: grant.oppNum || grant.source_id,
  id: grant.id,
  link: grant.link || grant.source_url,
}));

return [{ json: { grants: normalized, count: normalized.length } }];

// Node 4: split filtered grants into ~300-grant chunks and emit one n8n item per chunk.
// Execute Workflow (mode 'each') then runs the sub-workflow once per item.

const CHUNK_SIZE = 300;

const filterOut = $('Filter New Grants').first().json;
if (filterOut.noNewGrants || !Array.isArray(filterOut.grants) || filterOut.grants.length === 0) {
  return [{ json: { noNewGrants: true } }];
}

let orgId, callbackUrl;
try {
  const body = $('Fetch Grants Webhook').first().json.body;
  orgId = body?.org_id;
  callbackUrl = body?.callback_url || null;
} catch(e) {}

const ctx = $('Fetch Org Context').first().json;
if (ctx.error) return [{ json: ctx }];

const grants = filterOut.grants;
const totalChunks = Math.ceil(grants.length / CHUNK_SIZE);
const output = [];
for (let i = 0; i < totalChunks; i++) {
  output.push({
    json: {
      org_id: orgId,
      org: ctx.org,
      nicheSummary: ctx.nicheSummary,
      callbackUrl,
      chunk_index: i,
      total_chunks: totalChunks,
      grants: grants.slice(i * CHUNK_SIZE, (i + 1) * CHUNK_SIZE),
    }
  });
}
return output;

// Aggregate sub-workflow results and send final status
const items = $input.all();

let orgId, callbackUrl;
try {
  const webhookData = $('Fetch Grants Webhook').first().json.body;
  orgId = webhookData?.org_id;
  callbackUrl = webhookData?.callback_url;
} catch(e) {}

let totalInserted = 0;
let totalScreened = 0;
let totalGrants = 0;
for (const it of items) {
  const j = it.json || {};
  totalInserted += j.inserted || 0;
  totalScreened += j.screened || 0;
  totalGrants += j.total || 0;
}

if (callbackUrl && orgId) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: callbackUrl,
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
      },
      body: { org_id: orgId, status: 'complete', stage_message: 'Grant search complete!' }
    });
  } catch(e) {}
}

return [{ json: { success: true, totalInserted, totalScreened, totalGrants, chunks: items.length } }];

// Status callback helper: only sends status if callback_url exists (new org registration)
// This node is placed at different stages of the pipeline
const items = $input.all();

// Try to get webhook data
let callbackUrl, orgId, webhookSecret;
try {
  const webhookData = $('Fetch Grants Webhook').first().json.body;
  callbackUrl = webhookData?.callback_url;
  orgId = webhookData?.org_id;
  webhookSecret = webhookData?.is_new_org;
} catch(e) {
  // Not triggered via webhook (scheduled run) - skip status updates
  return items;
}

if (!callbackUrl || !orgId) return items;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: callbackUrl,
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
    },
    body: {
      org_id: orgId,
      status: 'searching',
      stage_message: 'Searching Grants.gov and federal databases...'
    }
  });
} catch(e) {
  // Don't fail the workflow if status update fails
}

return items;

// ============================================================
// Fetch Central Grants
// Pulls from the central_grants catalog instead of scraping
// external sources. The daily ingest workflow keeps the catalog
// fresh; this node just reads from it and hands rows downstream
// to Combine & Deduplicate → Dispatcher → Sub-workflow.
// ============================================================

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

const pageSize = 1000;
const selectCols = 'id,title,funder_name,organization,description,source,source_id,source_url,deadline,amount,eligibility,categories,metadata,last_seen_at';

let rows = [];
let offset = 0;
while (true) {
  const url = supabaseUrl + '/central_grants?select=' + selectCols + '&limit=' + pageSize + '&offset=' + offset + '&order=last_seen_at.desc';
  let page = [];
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey },
    });
    if (Array.isArray(res)) page = res;
  } catch (e) { break; }
  rows = rows.concat(page);
  if (page.length < pageSize) break;
  offset += pageSize;
}

// Drop expired grants. Null deadline = rolling/open-ended → keep.
const todayIso = new Date().toISOString().slice(0, 10);
const live = rows.filter(r => !r.deadline || r.deadline >= todayIso);

// Shape each row for downstream nodes. Dispatcher keys off `oppNum` for dedup.
return live.map(r => ({
  json: {
    id: r.id,
    oppNum: r.source_id || r.id,
    title: r.title || '',
    description: r.description || '',
    agency: r.funder_name || '',
    funder_name: r.funder_name || '',
    organization: r.organization || '',
    source: r.source || '',
    source_id: r.source_id || null,
    source_url: r.source_url || null,
    link: r.source_url || null,
    deadline: r.deadline || null,
    closeDate: r.deadline || null,
    amount: r.amount || null,
    eligibility: r.eligibility || null,
    categories: r.categories || null,
    metadata: r.metadata || null,
  },
}));
